Code.Terraform:
```hcl
# Terraform：确保至少有 3 个数据节点并启用区域感知
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cluster_config {
    instance_type          = "m5.large.search"
    instance_count         = 3     # 关键：设置至少 3 个数据节点以实现容错
    zone_awareness_enabled = true  # 关键：启用跨可用区（区域感知）
  }
}
```
